let gameRunning = false;
let p1Name = 'Player 1';
let p2Name = 'Player 2';

// Player class
class Player {
    constructor(x, y, color, isP1) {
        this.x = x;
        this.y = y;
        this.width = 32;
        this.height = 48;
        this.vx = 0;
        this.vy = 0;
        this.speed = 4;
        this.jumpPower = -12;
        this.gravity = 0.6;
        this.grounded = false;
        this.color = color;
        this.isP1 = isP1;
        this.health = 100;
        this.maxHealth = 100;
        this.facing = isP1 ? 1 : -1;
        this.attacking = false;
        this.attackCooldown = 0;
        this.attackFrame = 0;
        this.hitstun = 0;
        this.invincible = 0;
        this.flash = 0;
    }

    update() {
        // Apply gravity
        this.vy += this.gravity;

        // Update position
        this.x += this.vx;
        this.y += this.vy;

        // Ground collision
        const groundY = canvas.height - 80;
        if (this.y + this.height > groundY) {
            this.y = groundY - this.height;
            this.vy = 0;
            this.grounded = true;
        }

        // Screen boundaries
        if (this.x < 0) this.x = 0;
        if (this.x + this.width > canvas.width) this.x = canvas.width - this.width;

        // Friction
        this.vx *= 0.85;

        // Cooldowns
        if (this.attackCooldown > 0) this.attackCooldown--;
        if (this.hitstun > 0) this.hitstun--;
        if (this.invincible > 0) this.invincible--;
        if (this.flash > 0) this.flash--;

        // Attack animation
        if (this.attacking) {
            this.attackFrame++;
            if (this.attackFrame > 15) {
                this.attacking = false;
                this.attackFrame = 0;
            }
        }
    }

    jump() {
        if (this.grounded && this.hitstun === 0) {
            this.vy = this.jumpPower;
            this.grounded = false;
            playSound('jump');
        }
    }

    attack(other) {
        if (this.attackCooldown === 0 && this.hitstun === 0 && !this.attacking) {
            this.attacking = true;
            this.attackFrame = 0;
            this.attackCooldown = 30;
            playSound('attack');

            // Check hit
            const attackRange = 50;
            const attackX = this.x + (this.facing > 0 ? this.width : -attackRange);
            const attackY = this.y + 10;

            if (other.invincible === 0 &&
                attackX < other.x + other.width &&
                attackX + attackRange > other.x &&
                attackY < other.y + other.height &&
                attackY + 30 > other.y) {

                const damage = 12;
                other.health -= damage;
                other.hitstun = 20;
                other.invincible = 40;
                other.flash = 40;
                other.vx = this.facing * 8;
                other.vy = -5;
                playSound('hit');

                // Create particles
                for (let i = 0; i < 8; i++) {
                    particles.push(new Particle(other.x + other.width/2, other.y + other.height/2));
                }
            }
        }
    }

    draw() {
        // Flash when hit
        if (this.flash > 0 && this.flash % 4 < 2) return;

        // Draw pixel character
        const pixelSize = 4;
        const px = Math.floor(this.x / pixelSize) * pixelSize;
        const py = Math.floor(this.y / pixelSize) * pixelSize;

        // Body
        ctx.fillStyle = this.color;
        ctx.fillRect(px + 8, py + 16, 16, 24);

        // Head
        ctx.fillStyle = '#ffdbac';
        ctx.fillRect(px + 8, py, 16, 16);

        // Eyes
        ctx.fillStyle = '#000';
        if (this.facing > 0) {
            ctx.fillRect(px + 18, py + 6, 4, 4);
        } else {
            ctx.fillRect(px + 10, py + 6, 4, 4);
        }

        // Arms
        ctx.fillStyle = this.color;
        if (this.attacking) {
            // Attack pose
            const armExtend = this.attackFrame < 8 ? this.attackFrame * 3 : (15 - this.attackFrame) * 3;
            if (this.facing > 0) {
                ctx.fillRect(px + 24, py + 18, 8 + armExtend, 6);
            } else {
                ctx.fillRect(px - armExtend, py + 18, 8 + armExtend, 6);
            }
        } else {
            ctx.fillRect(px, py + 18, 8, 6);
            ctx.fillRect(px + 24, py + 18, 8, 6);
        }

        // Legs
        ctx.fillStyle = '#333';
        ctx.fillRect(px + 8, py + 40, 6, 8);
        ctx.fillRect(px + 18, py + 40, 6, 8);

        // Draw name above player
        ctx.fillStyle = '#fff';
        ctx.font = 'bold 12px Courier New';
        ctx.textAlign = 'center';
        const name = this.isP1 ? p1Name : p2Name;
        ctx.fillText(name, px + 16, py - 8);

        // Attack effect
        if (this.attacking && this.attackFrame < 10) {
            ctx.fillStyle = `rgba(255, 255, 0, ${1 - this.attackFrame/10})`;
            const fx = this.facing > 0 ? px + 32 : px - 20;
            ctx.fillRect(fx, py + 10, 20, 20);
        }
    }
}

