    let p1Name = 'Player 1', p2Name = 'Player 2';
    let currentMap = 0;

    class Player {
        constructor(x, y, color, isP1) {
            this.x = x; this.y = y;
            this.width = 32; this.height = 48;
            this.vx = 0; this.vy = 0;
            this.speed = 5; this.jumpPower = -14;
            this.gravity = 0.7; this.grounded = false;
            this.color = color; this.isP1 = isP1;
            this.health = 100; this.maxHealth = 100;
            this.facing = isP1 ? 1 : -1;
            this.attacking = false; this.attackCooldown = 0;
            this.attackFrame = 0; this.hitstun = 0;
            this.invincible = 0; this.flash = 0;
        }

        update() {
            this.vy += this.gravity;
            this.x += this.vx;
            this.y += this.vy;

            const groundY = canvas.height - 80;
            if (this.y + this.height > groundY) {
                this.y = groundY - this.height;
                this.vy = 0; this.grounded = true;
            }

            if (this.x < 0) { this.x = 0; this.vx = 0; }
            if (this.x + this.width > canvas.width) { 
                this.x = canvas.width - this.width; this.vx = 0; 
            }

            this.vx *= this.grounded ? 0.85 : 0.98;

            if (this.attackCooldown > 0) this.attackCooldown--;
            if (this.hitstun > 0) this.hitstun--;
            if (this.invincible > 0) this.invincible--;
            if (this.flash > 0) this.flash--;

            if (this.attacking) {
                this.attackFrame++;
                if (this.attackFrame > 12) {
                    this.attacking = false; this.attackFrame = 0;
                }
            }
        }

        jump() {
            if (this.grounded && this.hitstun === 0) {
                this.vy = this.jumpPower; this.grounded = false;
                playSound('jump');
            }
        }

        attack(other) {
            if (this.attackCooldown === 0 && this.hitstun === 0 && !this.attacking) {
                this.attacking = true; this.attackFrame = 0; this.attackCooldown = 25;
                playSound('attack');

                const attackRange = 45;
                const attackX = this.x + (this.facing > 0 ? this.width : -attackRange);
                const attackY = this.y + 10;

                if (other.invincible === 0 &&
                    attackX < other.x + other.width &&
                    attackX + attackRange > other.x &&
                    attackY < other.y + other.height &&
                    attackY + 30 > other.y) {

                    other.health = Math.max(0, other.health - 10);
                    other.hitstun = 15; other.invincible = 35; other.flash = 35;
                    other.vx = this.facing * 10; other.vy = -6;
                    playSound('hit');

                    for (let i = 0; i < 6; i++) {
                        particles.push(new Particle(other.x + other.width/2, other.y + other.height/2));
                    }
                }
            }
        }

        draw() {
            if (this.flash > 0 && Math.floor(this.flash / 4) % 2 === 0) return;

            const px = Math.floor(this.x);
            const py = Math.floor(this.y);

            ctx.fillStyle = this.color;
            ctx.fillRect(px + 8, py + 16, 16, 24);

            ctx.fillStyle = '#ffdbac';
            ctx.fillRect(px + 8, py, 16, 16);

            ctx.fillStyle = '#000';
            if (this.facing > 0) ctx.fillRect(px + 18, py + 6, 4, 4);
            else ctx.fillRect(px + 10, py + 6, 4, 4);

            ctx.fillStyle = this.color;
            if (this.attacking) {
                const armExtend = this.attackFrame < 6 ? this.attackFrame * 4 : (12 - this.attackFrame) * 2;
                if (this.facing > 0) ctx.fillRect(px + 24, py + 18, 8 + armExtend, 6);
                else ctx.fillRect(px - armExtend, py + 18, 8 + armExtend, 6);
            } else {
                ctx.fillRect(px, py + 18, 8, 6);
                ctx.fillRect(px + 24, py + 18, 8, 6);
            }

            ctx.fillStyle = '#333';
            ctx.fillRect(px + 8, py + 40, 6, 8);
            ctx.fillRect(px + 18, py + 40, 6, 8);

            ctx.fillStyle = '#fff';
            ctx.font = 'bold 12px Courier New, monospace';
            ctx.textAlign = 'center';
            ctx.fillText(this.isP1 ? p1Name : p2Name, px + 16, py - 8);

            if (this.attacking && this.attackFrame < 8) {
                ctx.fillStyle = `rgba(255, 255, 100, ${1 - this.attackFrame/8})`;
                const fx = this.facing > 0 ? px + 30 : px - 18;
                ctx.fillRect(fx, py + 8, 20, 24);
            }
        }
    }

    class Particle {
        constructor(x, y) {
            this.x = x; this.y = y;
            this.vx = (Math.random() - 0.5) * 10;
            this.vy = (Math.random() - 0.5) * 10;
            this.life = 25;
